INSERT INTO job_postings (id, user_id, title, description, requirements, location, salary_range, work_type, status, public_slug, company_name, company_logo_url, brand_color, created_at, updated_at)
VALUES
  ('1478228F-44DB-4AEC-94EA-0176D093CE9D', 'DF2A4ABF-6754-447B-A179-E02D4D16B502', 'Operador(a) de Loja - Arapiraca/AL - Partage Arapiraca', '<p>Respons&aacute;vel pelo atendimento humanizado ao cliente, aplica&ccedil;&atilde;o de t&eacute;cnicas de vendas, alcance de metas e opera&ccedil;&atilde;o de caixa. Suas atividades incluem abertura e fechamento da loja, organiza&ccedil;&atilde;o e reposi&ccedil;&atilde;o de produtos, controle de estoque, apoio no recebimento de mercadorias e alinhamento com as diretrizes comerciais e de Visual Merchandising, garantindo a excel&ecirc;ncia na experi&ecirc;ncia do cliente e o bom funcionamento da loja.</p> <h3>Principais atividades:</h3> <ul> <li>Realizar atendimento humanizado e atencioso aos clientes, garantindo uma experi&ecirc;ncia de compra positiva.</li> <li>Aplicar t&eacute;cnicas de vendas consultivas, buscando entender as necessidades dos clientes e oferecendo os produtos mais adequados.</li> <li>Cumprir as metas de vendas individuais e/ou coletivas, buscando sempre a supera&ccedil;&atilde;o dos resultados.</li> <li>Operar o caixa: registrar vendas, processar pagamentos, emitir notas fiscais e realizar o fechamento de caixa.</li> <li>Realizar abertura ou fechamento da loja, conforme escala e orienta&ccedil;&otilde;es.</li> <li>Organizar e manter a limpeza da loja, incluindo exposi&ccedil;&atilde;o adequada dos produtos, reposi&ccedil;&atilde;o de mercadorias nas prateleiras e organiza&ccedil;&atilde;o geral do ambiente.</li> <li>Zelar pela organiza&ccedil;&atilde;o e controle do estoque, verificando validade, precifica&ccedil;&atilde;o e acondicionamento correto dos produtos.</li> <li>Receber e conferir mercadorias entregues pelos fornecedores, reportando eventuais diverg&ecirc;ncias.</li> <li>Informar os clientes sobre promo&ccedil;&otilde;es vigentes, tirar d&uacute;vidas e fornecer orienta&ccedil;&otilde;es de uso dos produtos.</li> <li>Apoiar os demais departamentos da loja quando necess&aacute;rio, contribuindo para o bom funcionamento da opera&ccedil;&atilde;o como um todo.</li> </ul> <h3>Habilidades Espec&iacute;ficas:</h3> <ul> <li>Boa comunica&ccedil;&atilde;o e simpatia no contato com o p&uacute;blico</li> <li>Foco em resultados e no atendimento ao cliente</li> <li>Proatividade para identificar oportunidades de venda e melhorias no atendimento</li> <li>Aten&ccedil;&atilde;o e cuidado no atendimento e nas atividades do dia a dia</li> <li>Organiza&ccedil;&atilde;o e aten&ccedil;&atilde;o a detalhes para manter a loja e o estoque em ordem</li> <li>Trabalho em equipe e bom relacionamento interpessoal</li> <li>Flexibilidade e adaptabilidade a diferentes situa&ccedil;&otilde;es e demandas</li> </ul> <h3>Requisitos:</h3> <ul> <li>Ensino M&eacute;dio completo</li> <li>Idade a partir de 25 anos</li> <li>Disponibilidade de hor&aacute;rio para trabalhar em escala 6x1 (inclusive finais de semana e feriados, conforme necessidade da loja)</li> <li>No&ccedil;&otilde;es b&aacute;sicas de inform&aacute;tica (para opera&ccedil;&atilde;o de caixa e sistemas de vendas)</li> <li>Gostar de trabalhar com atendimento ao p&uacute;blico e vendas</li> </ul> <p><strong>Diferenciais:</strong></p> <ul> <li>Experi&ecirc;ncia anterior no varejo, especialmente em lojas de moda, beleza, cosm&eacute;ticos ou perfumaria</li> <li>Conhecimento b&aacute;sico em maquiagem e produtos de beleza</li> <li>Facilidade de aprendizado e interesse por tend&ecirc;ncias do segmento</li> </ul>', 'Escolaridade: Ensino Médio - Completo', 'Arapiraca, AL', 'R$ 1.540,00', 'onsite', 'active', 'operadora-de-loja-arapiraca-al-partage-arapiraca', 'Lets Make', 'https://iili.io/qBsrwL7.md.png', '#f45c6e', '2026-02-26T21:03:11.3899780+00:00'::timestamptz, '2026-03-02T11:36:20.3821592+00:00'::timestamptz),
