ON CONFLICT (id) DO NOTHING;

-- ===================
-- PARTE 3: CORREÇÕES PÓS-INSERT
-- ===================

-- 3a. Corrigir resume_filename: extrair apenas o nome do arquivo da URL
-- Para candidaturas onde resume_filename é uma URL completa, extrair o UUID+extensão
UPDATE job_applications
SET resume_filename = regexp_replace(
  replace(resume_url, '%2F', '/'),
  '^.*/([^/]+)$',
  '\1'
)
WHERE resume_url IS NOT NULL
  AND resume_filename LIKE 'https://%'
  AND job_posting_id IN (
    SELECT id FROM job_postings WHERE user_id = 'DF2A4ABF-6754-447B-A179-E02D4D16B502'
  );

-- 3b. Remover candidatura de teste (se foi inserida)
DELETE FROM job_applications WHERE id = 'CE42D118-2886-4702-AAB2-E948A965D59E';
